static inline u8 g_fun(u8 a,u8 b,u8 x){ u8 t=(u8)(a+b+x); return (u8)((t<<2)|(t>>6)); }
static inline u8 ror2(u8 t){ return (u8)((t>>2)|(t<<6)); }

static u32 f_fun(u32 v){
  u8 x0=v&0xff,x1=(v>>8)&0xff,x2=(v>>16)&0xff,x3=(v>>24)&0xff;
  u8 y2=g_fun(x3^x2,x1^x0,1);
